                          (xdrproc_t) xdr_void, NULL,
                          (xdrproc_t) xdr_void, NULL,
                          ((struct timeval) { 3, 0 }))
               == RPC_CANTRECV);
  clnt_destroy (clnt);

  return 0;
}

