void
handle_signal (int signum)
{
  void *addresses[NUM_FUNCTIONS];
  char **symbols;
  int n;
  int i;

  /* Get the backtrace addresses.  */
  n = backtrace (addresses, sizeof (addresses) / sizeof (addresses[0]));
  printf ("Obtained backtrace with %d functions\n", n);
  /*  Check that there are at least seven functions.  */
  if (n < NUM_FUNCTIONS)
    {
      FAIL ();
      return;
    }
  /* Convert them to symbols.  */
  symbols = backtrace_symbols (addresses, n);
  /* Check that symbols were obtained.  */
  if (symbols == NULL)
    {
      FAIL ();
      return;
    }
  for (i = 0; i < n; ++i)
    printf ("Function %d: %s\n", i, symbols[i]);
  /* Check that the function names obtained are accurate.  */
  if (!match (symbols[0], "handle_signal"))
    {
      FAIL ();
      return;
    }

  /* Do not check name for signal trampoline or cancellable syscall
     wrappers (__syscall_cancel*).  */
  for (; i < n - 1; i++)
    if (match (symbols[i], "read"))
      break;
  if (i == n - 1)
    {
      FAIL ();
      return;
    }

  for (; i < n - 1; i++)
    if (!match (symbols[i], "fn"))
      {
	FAIL ();
	return;
      }
  /* Symbol names are not available for static functions, so we do not
     check do_test.  */

  /* Check that backtrace does not return more than what fits in the array
     (bug 25423).  */
  for (int j = 0; j < NUM_FUNCTIONS; j++)
    {
      n = backtrace (addresses, j);
      if (n > j)
	{
	  FAIL ();
	  return;
	}
    }
}

int
__backtrace (void **array, int size)
{
  struct layout *current;
  int count;

  /* Force gcc to spill LR.  */
  asm volatile ("" : "=l"(current));

  /* Get the address on top-of-stack.  */
  asm volatile ("lwz %0,0(1)" : "=r"(current));

  for (				count = 0;
       current != NULL && 	count < size;
       current = current->next, count++)
    {
      gregset_t *gregset = NULL;

      array[count] = current->return_address;

      /* Check if the symbol is the signal trampoline and get the interrupted
       * symbol address from the trampoline saved area.  */
      if (is_sigtramp_address (current->return_address))
	{
	  struct signal_frame_32 *sigframe =
	    (struct signal_frame_32*) current;
          gregset = &sigframe->mctx.gregs;
        }
      else if (is_sigtramp_address_rt (current->return_address))
	{
	  struct rt_signal_frame_32 *sigframe =
            (struct rt_signal_frame_32*) current;
          gregset = &sigframe->uc.uc_mcontext.uc_regs->gregs;
        }
      if (gregset)
	{
	  if (count + 1 == size)
	    break;
	  array[++count] = (void*)((*gregset)[PT_NIP]);
	  current = (void*)((*gregset)[PT_R1]);
	}
    }

  /* It's possible the second-last stack frame can't return
     (that is, it's __libc_start_main), in which case
     the CRT startup code will have set its LR to 'NULL'.  */
  if (count > 0 && array[count-1] == NULL)
    count--;

  return count;
}

int
__backtrace (void **array, int size)
{
  struct layout *current;
  int count;

  /* Force gcc to spill LR.  */
  asm volatile ("" : "=l"(current));

  /* Get the address on top-of-stack.  */
  asm volatile ("ld %0,0(1)" : "=r"(current));

  for (				count = 0;
       current != NULL && 	count < size;
       current = current->next, count++)
    {
      array[count] = current->return_address;

      /* Check if the symbol is the signal trampoline and get the interrupted
       * symbol address from the trampoline saved area.  */
      if (is_sigtramp_address (current->return_address))
        {
	  struct signal_frame_64 *sigframe = (struct signal_frame_64*) current;
	  if (count + 1 == size)
	    break;
          array[++count] = (void*) sigframe->uc.uc_mcontext.gp_regs[PT_NIP];
	  current = (void*) sigframe->uc.uc_mcontext.gp_regs[PT_R1];
	}
    }

  /* It's possible the second-last stack frame can't return
     (that is, it's __libc_start_main), in which case
     the CRT startup code will have set its LR to 'NULL'.  */
  if (count > 0 && array[count-1] == NULL)
    count--;

  return count;
}

int32_t
__ieee754_rem_pio2l (long double x, long double *y)
{
  double tx[3], ty[3];
  int32_t se, j0;
  uint32_t i0, i1;
  int sx;
  int n, exp;

  GET_LDOUBLE_WORDS (se, i0, i1, x);
  sx = (se >> 15) & 1;
  j0 = (se & 0x7fff) - 0x3fff;

  if (j0 < -1)
    {
      /* |x| < pi/4.  */
      y[0] = x;
      y[1] = 0;
      return 0;
    }

  if (j0 >= 0x8000)
    {
      /* x is infinite or NaN.  */
      y[0] = x - x;
      y[1] = y[0];
      return 0;
    }

  if ((i0 & 0x80000000) == 0)
    {
      /* Pseudo-zero and unnormal representations are not valid
	 representations of long double.  We need to avoid stack
	 corruption in __kernel_rem_pio2, which expects input in a
	 particular normal form, but those representations do not need
	 to be consistently handled like any particular floating-point
	 value.  */
      y[1] = y[0] = __builtin_nanl ("");
      return 0;
    }

  /* Split the 64 bits of the mantissa into three 24-bit integers
     stored in a double array.  */
  exp = j0 - 23;
  tx[0] = (double) (i0 >> 8);
  tx[1] = (double) (((i0 << 16) | (i1 >> 16)) & 0xffffff);
  tx[2] = (double) ((i1 << 8) & 0xffffff);

  n = __kernel_rem_pio2 (tx, ty, exp, 3, 2, two_over_pi);

  /* The result is now stored in two double values, we need to convert
     it into two long double values.  */
  if (sx == 0)
    {
      y[0] = (long double) ty[0] + (long double) ty[1];
      y[1] = ty[1] - (y[0] - ty[0]);
      return n;
    }
  else
    {
      y[0] = -((long double) ty[0] + (long double) ty[1]);
      y[1] = -ty[1] - (y[0] + ty[0]);
      return -n;
    }
}

static int
do_test (void)
{
  for (int i = 0; i < 64; i++)
    {
      uint64_t sig = i == 63 ? 0 : 1ULL << i;
      long double ld;
      SET_LDOUBLE_WORDS (ld, 0x4141,
			 sig >> 32, sig & 0xffffffffULL);
      /* The requirement is that no stack overflow occurs when the
	 pseudo-zero or unnormal goes through range reduction.  */
      volatile long double ldr;
      ldr = sinl (ld);
      (void) ldr;
    }
  return 0;
}

